2284 |     // --- CLIENT SIDE PATCH ENGINE (Smart Line-Matcher) ---
2285 |     function applyLocalPatch(content, ops) {
2286 |         let lines = content.split('\n');
2287 |         let logs = [];
2288 |         let success = true;
2289 | 
2290 |         if (typeof ops === 'string') {
2291 |             try { ops = JSON.parse(ops); } catch(e) { return { content, success: false, logs: ["Invalid JSON"]}; }
2292 |         }
2293 | 
2294 |         ops.forEach(op => {
2295 |             if (op.action === 'comment') return;
2296 |             if (op.action === 'create_file') { lines = op.content.split('\n'); logs.push('Created file'); return; }
2297 |             
2298 |             if (op.action === 'replace_block') {
2299 |                 // Strategy 1: Exact String Match (Fastest)
2300 |                 const currentStr = lines.join('\n');
2301 |                 if (currentStr.includes(op.find_block)) {
2302 |                     lines = currentStr.replace(op.find_block, op.replace_with).split('\n');
2303 |                     logs.push('Exact match applied');
2304 |                     return;
2305 |                 }
2306 | 
2307 |                 // Strategy 2: Line-by-Line Fuzzy Match (Whitespace Agnostic)
2308 |                 const searchLines = op.find_block.split('\n').map(l => l.trim()).filter(l => l !== '');
2309 |                 if (searchLines.length === 0) return;
2310 | 
2311 |                 let matchStart = -1;
2312 |                 let matchEnd = -1;
2313 | 
2314 |                 // Scan file lines
2315 |                 for (let i = 0; i < lines.length; i++) {
2316 |                     // If first line matches (ignoring whitespace)
2317 |                     if (lines[i].trim() === searchLines[0]) {
2318 |                         // Check subsequent lines
2319 |                         let allMatch = true;
2320 |                         let fileOffset = 0;
2321 |                         let searchOffset = 1;
2322 |                         
2323 |                         while (searchOffset < searchLines.length) {
2324 |                             if (i + fileOffset + 1 >= lines.length) { allMatch = false; break; }
2325 |                             const nextFile = lines[i + fileOffset + 1].trim();
2326 |                             // Skip empty lines in file if they aren't in search block
2327 |                             if (nextFile === '') {
2328 |                                 fileOffset++;
2329 |                                 continue;
2330 |                             }
2331 |                             if (nextFile !== searchLines[searchOffset]) {
2332 |                                 allMatch = false;
2333 |                                 break;
2334 |                             }
2335 |                             fileOffset++;
2336 |                             searchOffset++;
2337 |                         }
2338 | 
2339 |                         if (allMatch) {
2340 |                             matchStart = i;
2341 |                             matchEnd = i + fileOffset;
2342 |                             break;
2343 |                         }
2344 |                     }
2345 |                 }
2346 | 
2347 |                 if (matchStart !== -1) {
2348 |                     // Replace the range of lines
2349 |                     const replacement = op.replace_with.split('\n');
2350 |                     lines.splice(matchStart, (matchEnd - matchStart) + 1, ...replacement);
2351 |                     logs.push(`Fuzzy match applied (Lines ${matchStart+1}-${matchEnd+1})`);
2352 |                 } else {
2353 |                     success = false;
2354 |                     logs.push(`Failed to find block: "${op.find_block.substring(0, 30)}..."`);
2355 |                     console.warn("Patch Mismatch. File has:", content.substring(0, 200), "... vs Search:", op.find_block);
2356 |                 }
2357 |             }
2358 |         });
2359 |         return { content: lines.join('\n'), success, logs };
2360 |     }
