5409 |     async function jumpToElement(selector, tabId, navIndex, loadMoreFn) {
5410 |         console.group(`[DeepJump] Target: ${selector} in ${tabId}`);
5411 |         
5412 |         const navItems = document.querySelectorAll('.nav-item');
5413 |         switchTab(tabId, navItems[navIndex]);
5414 | 
5415 |         const scrollContainer = document.querySelector('.main-view');
5416 |         let retryCount = 0;
5417 |         const MAX_RETRIES = 5;
5418 | 
5419 |         const attemptNavigation = async () => {
5420 |             const element = document.querySelector(selector);
5421 |             
5422 |             if (element) {
5423 |                 console.log("[DeepJump] Element found. Scrolling...");
5424 |                 
5425 |                 // Wait for any tab transition animations
5426 |                 await new Promise(r => setTimeout(r, 300));
5427 | 
5428 |                 let offsetTop = 0;
5429 |                 let curr = element;
5430 |                 while (curr && curr !== scrollContainer) {
5431 |                     offsetTop += curr.offsetTop;
5432 |                     curr = curr.offsetParent;
5433 |                 }
5434 | 
5435 |                 const targetScroll = offsetTop - (scrollContainer.clientHeight / 2) + (element.clientHeight / 2);
5436 |                 scrollContainer.scrollTo({ top: targetScroll, behavior: 'smooth' });
5437 | 
5438 |                 // Visual Highlight
5439 |                 element.style.transition = 'all 0.5s ease';
5440 |                 element.style.backgroundColor = 'rgba(59, 130, 246, 0.3)';
