5444 |                     element.style.boxShadow = '';
5445 |                 }, 3000);
5446 |                 
5447 |                 console.groupEnd();
5448 |                 return true;
5449 |             }
5450 | 
5451 |             if (retryCount < MAX_RETRIES && loadMoreFn) {
5452 |                 console.log(`[DeepJump] Not found. Triggering loadMore (Attempt ${retryCount + 1})...`);
5453 |                 retryCount++;
5454 |                 showGlobalToast("أƒآƒأ‚آƒأƒآ‚أ‚آƒأƒآƒأ‚آ‚أƒآ‚أ‚آ°أƒآƒأ‚آƒأƒآ‚أ‚آ‚أƒآƒأ‚آ‚أƒآ‚أ‚آںأƒآƒأ‚آƒأƒآ‚أ‚آ‚أƒآƒأ‚آ‚أƒآ‚أ‚آ”أƒآƒأ‚آƒأƒآ‚أ‚آ‚أƒآƒأ‚آ‚أƒآ‚أ‚آچ Searching deeper...");
5455 |                 
5456 |                 await loadMoreFn(); 
5457 |                 await new Promise(r => setTimeout(r, 800)); // Wait for render
5458 |                 return attemptNavigation();
5459 |             }
5460 | 
5461 |             console.error("[DeepJump] Failed: Element not found after retries.");
5462 |             showGlobalToast("Entry not found in recent history.", true);
5463 |             console.groupEnd();
5464 |             return false;
5465 |         };
5466 | 
5467 |         setTimeout(attemptNavigation, 100);
