7919 |     function extractTableNames(sql) {
7920 |         if (!sql) return [];
7921 |         const tables = [];
7922 |         const systemNoise = ['columns', 'tables', 'schemata', 'information_schema'];
7923 |         
7924 |         // Pattern 1: Standard FROM/JOIN (handles schema.table and "table")
7925 |         const fromRegex = /(?:FROM|JOIN)\s+(?:(?:"?\w+"?\.)?"?(\w+)"?)/gi;
7926 |         // Pattern 2: Metadata queries (WHERE table_name = '...')
7927 |         const metaRegex = /table_name\s*=\s*'([^']+)'/gi;
7928 | 
7929 |         let match;
7930 |         while ((match = fromRegex.exec(sql)) !== null) {
7931 |             const name = match[1];
7932 |             if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
7933 |                 tables.push(name);
7934 |             }
7935 |         }
7936 |         
7937 |         while ((match = metaRegex.exec(sql)) !== null) {
7938 |             const name = match[1];
7939 |             if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
7940 |                 tables.push(name);
7941 |             }
7942 |         }
7943 | 
7944 |         return tables;
7945 |     }
